func (sched *Scheduler) ScheduleOne(ctx context.Context) {
    // The scheduling cycle: synchronous, one pod, start to finish.
    scheduleResult, assumedPodInfo, status := sched.schedulingCycle(
        schedulingCycleCtx, state, fwk, podInfo, start, podsToActivate)
    if !status.IsSuccess() {
        // A failed cycle does not crash — it re-queues the pod.
        sched.FailureHandler(schedulingCycleCtx, fwk, assumedPodInfo, status, ...)
        return
    }

    // bind the pod to its host asynchronously
    // (we can do this b/c of the assumption step above).
    go sched.runBindingCycle(ctx, state, fwk, scheduleResult, assumedPodInfo, ...)
}
